from itertools import count
def bgen():
    for L in count(3):
        for d1 in range(1, 10):
            base = d1*10**(L-1)
            for i in range(L-2):
                for d2 in range(1, 10):
                    yield base + d2*10**i
def a(n):
    return next(m//n for m in bgen() if m%n == 0) if n else 0
print([a(n) for n in range(111)])

